import requests
import json

class ApiClient:
    def __init__(self, base_url):
        self.base_url = base_url
        self.session = requests.Session()
        self.token = None

    def login(self, username, password):
        url = f"{self.base_url}/login"
        payload = {"username": username, "password": password}
        headers = {"Content-Type": "application/json"}
        response = self.session.post(url, data=json.dumps(payload), headers=headers)

        if response.status_code == 200:
            data = response.json()
            self.token = data.get("token")
            return True
        else:
            print(f"Giriş başarısız: {response.status_code} - {response.text}")
            return False

    def get(self, endpoint):
        url = f"{self.base_url}/{endpoint}"
        headers = {"Authorization": f"Bearer {self.token}"} if self.token else {}
        response = self.session.get(url, headers=headers)

        if response.status_code == 200:
            return response.json()
        else:
            print(f"GET isteği başarısız: {response.status_code} - {response.text}")
            return None

    def post(self, endpoint, data):
        url = f"{self.base_url}/{endpoint}"
        headers = {"Content-Type": "application/json", "Authorization": f"Bearer {self.token}"} if self.token else {"Content-Type": "application/json"}
        response = self.session.post(url, data=json.dumps(data), headers=headers)

        if response.status_code in [200, 201]:
            return response.json()
        else:
            print(f"POST isteği başarısız: {response.status_code} - {response.text}")
            return None

    def put(self, endpoint, data):
        url = f"{self.base_url}/{endpoint}"
        headers = {"Content-Type": "application/json", "Authorization": f"Bearer {self.token}"} if self.token else {"Content-Type": "application/json"}
        response = self.session.put(url, data=json.dumps(data), headers=headers)

        if response.status_code == 200:
            return response.json()
        else:
            print(f"PUT isteği başarısız: {response.status_code} - {response.text}")
            return None

    def delete(self, endpoint):
        url = f"{self.base_url}/{endpoint}"
        headers = {"Authorization": f"Bearer {self.token}"} if self.token else {}
        response = self.session.delete(url, headers=headers)

        if response.status_code == 204:
            return True
        else:
            print(f"DELETE isteği başarısız: {response.status_code} - {response.text}")
            return False

    def logout(self):
        self.token = None
        self.session.close()
        print("Çıkış yapıldı.")
